package main

import (
	"fmt"
	"os/exec"
)

func ConvertImage(inputFile, outputFile, format string) error {
	command := fmt.Sprintf("convert %s -resize 800x600! %s.%s", inputFile, outputFile+".tmp", format)
	cmd := exec.Command("sh", "-c", command)
	err := cmd.Run()
	if err != nil {
		return err
	}
	renameCmd := exec.Command("mv", outputFile + ".tmp."+format, outputFile+"."+format)
	renameErr := renameCmd.Run()
	return renameErr
}